import java.util.*;
import java.util.stream.*;

public class Main {

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        List<String> words = new ArrayList<>(); while (input.hasNext()) words.add(input.next());
        words.sort((left, right) -> { int byLength = Integer.compare(left.length(), right.length()); return byLength != 0 ? byLength : left.compareTo(right); });
        System.out.println(String.join(" " , words));
    }
}
